create table dirkspzm32.aps_plan_ausfuehrung_kpi (
    sid                  varchar2(2 char) default '01' not null enable,
    firma_nr             number(6, 0) default 1 not null enable,
    aps_plan_stufe_id    number(*, 0) not null enable,
    aps_plan_stufe_text  varchar2(200 char) not null enable,
    counter              number(*, 5) default 0 not null enable,
    exec_ms_sum          number(*, 5) default 0,
    exec_ms_min          number(*, 5) default 0,
    exec_ms_max          number(*, 5) default 0,
    exec_ms_last         number(*, 5) default 0,
    exec_date_start_min  date,
    exec_date_start_max  date,
    exec_date_start_last date,
    exec_params_min      varchar2(4000 char),
    exec_params_max      varchar2(4000 char),
    exec_params_last     varchar2(4000 char),
    exec_bedarf_min      number(*, 3),
    exec_bedarf_max      number(*, 3),
    exec_bedarf_last     number(*, 3),
    exec_ergebnis_min    number(*, 3),
    exec_ergebnis_max    number(*, 3),
    exec_ergebnis_last   number(*, 3)
);

alter table dirkspzm32.aps_plan_ausfuehrung_kpi
    add constraint pk_aps_plan_kpi
        primary key ( firma_nr,
                      sid,
                      aps_plan_stufe_id )
            using index enable;


